const body = $input.first().json.body;

const request_id = body.request_id || 'req-' + Date.now().toString(36) + Math.random().toString(36).slice(2,8);
const text = (body.text || '').trim();
const images = Array.isArray(body.images) ? body.images : [];
const task_type = body.task_type || 'auto';

const has_text = text.length > 0;
const has_images = images.length > 0;

return [{
  json: {
    request_id,
    text,
    images,
    task_type,
    has_text,
    has_images
  }
}];

const input = $('NormalizeInput').first().json;
const agentOutput = $input.first().json;

let vision_result = null;
let text_result = null;
let report_from_agent = null;
const agent_trace = [];

const steps = agentOutput.intermediateSteps || [];
for (const step of steps) {
  const toolName = (step.action && step.action.tool) || '';
  const obs = step.observation || '';
  let parsed = null;
  try {
    parsed = typeof obs === 'string' ? JSON.parse(obs) : obs;
  } catch (e) { /* not JSON */ }

  if (toolName.includes('vision')) {
    vision_result = parsed;
    agent_trace.push({ step: 'tool_call', tool: 'vision_tool', status: parsed ? 'ok' : 'error' });
  } else if (toolName.includes('text') && !toolName.includes('report')) {
    text_result = parsed;
    agent_trace.push({ step: 'tool_call', tool: 'text_tool', status: parsed ? 'ok' : 'error' });
  } else if (toolName.includes('report')) {
    report_from_agent = parsed;
  }
}

if (!vision_result && input.has_images) {
  try {
    vision_result = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/tool/vision',
      body: { request_id: input.request_id, images: input.images },
      headers: { 'Content-Type': 'application/json' },
      timeout: 120000
    });
    agent_trace.push({ step: 'tool_call', tool: 'vision_tool', status: 'ok' });
  } catch (e) {
    agent_trace.push({ step: 'tool_call', tool: 'vision_tool', status: 'error', error: e.message });
  }
}

if (!text_result && input.has_text) {
  try {
    text_result = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/tool/text',
      body: { request_id: input.request_id, text: input.text },
      headers: { 'Content-Type': 'application/json' },
      timeout: 120000
    });
    agent_trace.push({ step: 'tool_call', tool: 'text_tool', status: 'ok' });
  } catch (e) {
    agent_trace.push({ step: 'tool_call', tool: 'text_tool', status: 'error', error: e.message });
  }
}

const tools_used = [];
if (vision_result) tools_used.push('vision');
if (text_result) tools_used.push('text');
tools_used.push('report');
const decision = 'called ' + tools_used.join('+') + ' then report';
const trace = [{ step: 'orchestrator', decision }, ...agent_trace];

const hasVisionOk = !input.has_images || (report_from_agent && report_from_agent.findings && report_from_agent.findings.vision && Array.isArray(report_from_agent.findings.vision.top_objects) && report_from_agent.findings.vision.top_objects.length > 0);
const hasTextOk = !input.has_text || (report_from_agent && report_from_agent.findings && report_from_agent.findings.text && report_from_agent.findings.text.label && report_from_agent.findings.text.label !== 'null');
if (report_from_agent && report_from_agent.request_id && report_from_agent.summary && typeof report_from_agent.summary === 'string' && report_from_agent.summary.trim().length > 0 && hasVisionOk && hasTextOk) {
  report_from_agent.trace = trace;
  return [{ json: report_from_agent }];
}

trace.push({ step: 'tool_call', tool: 'report_tool' });
try {
  const reportResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://localhost:5678/webhook/tool/report',
    body: {
      request_id: input.request_id,
      original_input: { text: input.text, images: input.images, task_type: input.task_type },
      vision_result,
      text_result,
      trace
    },
    headers: { 'Content-Type': 'application/json' },
    timeout: 600000
  });
  return [{ json: reportResp }];
} catch (e) {
  return [{ json: {
    request_id: input.request_id,
    summary: 'Report generation failed: ' + e.message,
    findings: { vision: { top_objects: [], details: [] }, text: { label: null, confidence: null, entities: [] } },
    recommendations: ['Retry the analysis or check the LLM service.'],
    trace,
    errors: ['Report tool error: ' + e.message]
  }}];
}
